global $conn;

while ($record = $button->getNextSelectedRecord())
{
    // ambil username dari record terpilih
    $username = $record["username"];   // sesuaikan nama field

    if (!empty($username)) {

        // amankan string
        $username = db_prepare_string($username);

        $sql = "INSERT INTO ugmembers (UserName, GroupID, Provider)
                VALUES ($username, '1', '')
                ON DUPLICATE KEY UPDATE GroupID='1'";

        db_exec($sql, $conn);
    }
}
